DROP POLICY IF EXISTS "Admin Upload" ON storage.objects; CREATE POLICY "Admin Upload" ON storage.objects FOR INSERT TO authenticated WITH CHECK (bucket_id = 'portfolio-assets'); DROP POLICY IF EXISTS "Admin Update" ON storage.objects; CREATE POLICY "Admin Update" ON storage.objects FOR UPDATE TO authenticated USING (bucket_id = 'portfolio-assets'); DROP POLICY IF EXISTS "Admin Delete" ON storage.objects; CREATE POLICY "Admin Delete" ON storage.objects FOR DELETE TO authenticated USING (bucket_id = 'portfolio-assets');
